 * Model Router - Multi-model routing based on task characteristics
 *
 * Converted from Python to TypeScript for performance
 */
// ============================================================================
// Types
// ============================================================================
export var ModelProvider;
(function (ModelProvider) {
    ModelProvider["OPENAI"] = "openai";
    ModelProvider["ANTHROPIC"] = "anthropic";
    ModelProvider["OPENROUTER"] = "openrouter";
    ModelProvider["CUSTOM"] = "custom";
})(ModelProvider || (ModelProvider = {}));
// ============================================================================
// Model Router
// ============================================================================
export class ModelRouter {
    providers = new Map();
    models = new Map();
    policies = [];
    routingCache = new Map();
    cacheTTL = 60; // 1 minute
    addProvider(provider, config) {
        this.providers.set(provider, config);
    }
    addModel(endpoint) {
        this.models.set(endpoint.modelName, endpoint);
    }
    addPolicy(policy) {
        this.policies.push(policy);
    }
    pickModel(taskType, costConstraint, latencyConstraint) {
        const start = Date.now();
        // Check cache
        const cacheKey = `${taskType}:${costConstraint}:${latencyConstraint}`;
        const cached = this.routingCache.get(cacheKey);
        if (cached && cached.cachedAt && Date.now() - cached.cachedAt < this.cacheTTL * 1000) {
            return cached;
        }
        // Find matching policy
        const policy = this.findMatchingPolicy(taskType);
        let candidates = [];
        if (policy) {
            // Use policy's model preferences
            const allModels = [policy.primaryModel, ...policy.fallbackModels];
            for (const modelName of allModels) {
                const model = this.models.get(modelName);
                if (model && this.matchesConstraints(model, costConstraint, latencyConstraint)) {
                    candidates.push(model);
                }
            }
        }
        else {
            // No policy - find any matching model
            for (const model of this.models.values()) {
                if (this.matchesConstraints(model, costConstraint, latencyConstraint)) {
                    candidates.push(model);
                }
            }
        }
        // Sort by cost * latency (optimal balance)
        candidates.sort((a, b) => (a.costPerToken * a.latencyP50Ms) - (b.costPerToken * b.latencyP50Ms));
        if (candidates.length > 0) {
            const selected = candidates[0];
            selected.cachedAt = Date.now();
            this.routingCache.set(cacheKey, selected);
            return selected;
        }
        return null;
    }
    findMatchingPolicy(taskType) {
        for (const policy of this.policies) {
            if (this.matchPattern(taskType, policy.taskTypePattern)) {
                return policy;
            }
        }
        return null;
    }
    matchPattern(text, pattern) {
        // Simple glob-like matching
        if (pattern === '*')
            return true;
        const regex = pattern
            .replace(/\*/g, '.*')
            .replace(/\?/g, '.');
        return new RegExp(`^${regex}$`).test(text);
    }
    matchesConstraints(model, costConstraint, latencyConstraint) {
        if (costConstraint !== undefined) {
            const estimatedCost = model.costPerToken * 1000;
            if (estimatedCost > costConstraint)
                return false;
        }
        if (latencyConstraint !== undefined) {
            if (model.latencyP50Ms / 1000 > latencyConstraint)
                return false;
        }
        return true;
    }
    getModelInfo(modelName) {
        const model = this.models.get(modelName);
        if (!model)
            return null;
        return {
            name: model.modelName,
            provider: model.provider,
            cost_per_token: model.costPerToken,
            token_limit: model.tokenLimit,
            latency_p50_ms: model.latencyP50Ms,
            gpu_required: model.gpuRequired,
            features: {
                functions: model.supportsFunctions,
                vision: model.supportsVision,
            },
        };
    }
    listModels(provider) {
        if (provider) {
            return Array.from(this.models.values()).filter((m) => m.provider === provider);
        }
        return Array.from(this.models.values());
    }
    getStats() {
        return {
            totalModels: this.models.size,
            providers: Array.from(this.providers.keys()),
            policies: this.policies.length,
            cacheSize: this.routingCache.size,
        };
    }
}
// ============================================================================
// Model Router Builder
// ============================================================================
export class ModelRouterBuilder {
    static createDefaultRouter() {
