    "content": "/**
 * L1-L5 Memory Layers Implementation
 *
 * Based on spec.json memory_layer requirements:
 * - L1: WorkingMemory (in-memory, 30s TTL, ≤100ms)
 * - L2: ConversationHistory (7 days TTL, ≤100ms)
 * - L3: UserProfile (30 days TTL, ≤300ms)
 * - L4: ProceduralMemory/Skills (permanent, ≤300ms)
 * - L5: ReplayCases (90 days TTL, ≤500ms)
 */
import { success, failure } from '../core/result.js';
import { ErrorCode, createError } from '../core/error.js';
// ============================================================================
// Types
// ============================================================================
export var MemoryLayer;
(function (MemoryLayer) {
    MemoryLayer["L1_WORKING"] = "L1";
    MemoryLayer["L2_CONVERSATION"] = "L2";
    MemoryLayer["L3_USER_PROFILE"] = "L3";
    MemoryLayer["L4_PROCEDURAL"] = "L4";
    MemoryLayer["L5_REPLAY"] = "L5";
})(MemoryLayer || (MemoryLayer = {}));
// ============================================================================
// Constants
// ============================================================================
export const DEFAULT_TTLs = {
    [MemoryLayer.L1_WORKING]: 30, // 30 seconds
    [MemoryLayer.L2_CONVERSATION]: 604800, // 7 days
    [MemoryLayer.L3_USER_PROFILE]: 2592000, // 30 days
    [MemoryLayer.L4_PROCEDURAL]: -1, // permanent (-1 means no expiry)
    [MemoryLayer.L5_REPLAY]: 7776000, // 90 days
};
export const DEFAULT_LATENCY_SLA = {
    L1: 0.1, // 100ms
    L2: 0.1, // 100ms
    L3: 0.3, // 300ms
    L4: 0.3, // 300ms
    L5: 0.5, // 500ms
};
export const DEFAULT_CONFIG = {
    ttls: DEFAULT_TTLs,
    latencySLA: DEFAULT_LATENCY_SLA,
};
// ============================================================================
// Memory Layer Store
// ============================================================================
export class MemoryLayers {
    stores = new Map();
    config;
    stats = new Map();
    constructor(config = {}) {
        this.config = {
            ttls: config.ttls || DEFAULT_TTLs,
            latencySLA: config.latencySLA || DEFAULT_LATENCY_SLA,
        };
        // Initialize stores for each layer
        for (const layer of Object.values(MemoryLayer)) {
            this.stores.set(layer, new Map());
            this.stats.set(layer, {
                layer,
                itemCount: 0,
                totalHits: 0,
                avgLatencyMs: 0,
                hitRate: 0,
            });
        }
    }
    /**
     * Store an item in the specified layer
     */
    async set(layer, key, value, ttl) {
        try {
            const store = this.stores.get(layer);
            if (!store) {
                return failure(createError(ErrorCode.VALIDATION_FAILED, `Invalid memory layer: ${layer}`));
            }
            const layerTtl = ttl ?? this.config.ttls[layer];
            const now = Date.now();
            const expiresAt = layerTtl > 0 ? now + (layerTtl * 1000) : -1;
            const item = {
                key,
                value,
                layer,
                createdAt: now,
                expiresAt,
                hitCount: 0,
                lastAccessedAt: now,
            };
            store.set(key, item);
            this.updateStats(layer);
            return success(undefined);
        }
        catch (error) {
            return failure(createError(ErrorCode.INTERNAL, `Failed to set memory item: ${error instanceof Error ? error.message : String(error)}`));
        }
    }
    /**
     * Get an item from the specified layer
     */
    async get(layer, key) {
        try {
            const store = this.stores.get(layer);
            if (!store) {
                return failure(createError(ErrorCode.VALIDATION_FAILED, `Invalid memory layer: ${layer}`));
            }
            const item = store.get(key);
            if (!item) {
                return success(null);
            }
            // Check expiry
            if (item.expiresAt > 0 && Date.now() > item.expiresAt) {
                store.delete(key);
                this.updateStats(layer);
                return success(null);
            }
            // Update access stats
            item.hitCount++;
            item.lastAccessedAt = Date.now();
            return success(item.value);
        }
        catch (error) {
            return failure(createError(ErrorCode.INTERNAL, `Failed to get memory item: ${error instanceof Error ? error.message : String(error)}`));
        }
    }
    /**
     * Delete an item from the specified layer
     */
    async delete(layer, key) {
        try {
            const store = this.stores.get(layer);
            if (!store) {
                return failure(createError(ErrorCode.VALIDATION_FAILED, `Invalid memory layer: ${layer}`));
            }
            const deleted = store.delete(key);
            this.updateStats(layer);
            return success(deleted);
        }
        catch (error) {
            return failure(createError(ErrorCode.INTERNAL, `Failed to delete memory item: ${error instanceof Error ? error.message : String(error)}`));
        }
    }
    /**
     * Find items matching a pattern in a layer
     */
    async find(layer, predicate) {
        try {
            const store = this.stores.get(layer);
            if (!store) {
                return failure(createError(ErrorCode.VALIDATION_FAILED, `Invalid memory layer: ${layer}`));
            }
            const results = [];
            const now = Date.now();
            for (const [key, item] of store) {
                // Skip expired items
                if (item.expiresAt > 0 && now > item.expiresAt) {
                    store.delete(key);
                    continue;
                }
                if (predicate(item)) {
                    results.push(item.value);
                }
            }
            this.updateStats(layer);
            return success(results);
        }
        catch (error) {
            return failure(createError(ErrorCode.INTERNAL, `Failed to find memory items: ${error instanceof Error ? error.message : String(error)}`));
        }
    }
    /**
     * Clear a specific layer
     */
    async clear(layer) {
        try {
            const store = this.stores.get(layer);
            if (!store) {
                return failure(createError(ErrorCode.VALIDATION_FAILED, `Invalid memory layer: ${layer}`));
            }
            store.clear();
            this.updateStats(layer);
            return success(undefined);
        }
        catch (error) {
            return failure(createError(ErrorCode.INTERNAL, `Failed to clear memory layer: ${error instanceof Error ? error.message : String(error)}`));
        }
    }
    /**
     * Get statistics for a layer
     */
    getStats(layer) {
        return this.stats.get(layer) || null;
    }
    /**
     * Get all statistics
     */
    getAllStats() {
        return Array.from(this.stats.values());
    }
    /**
     * Cleanup expired items in all layers
     */
    async cleanup() {
        try {
            let cleaned = 0;
            const now = Date.now();
            for (const [layer, store] of this.stores) {
                for (const [key, item] of store) {
                    if (item.expiresAt > 0 && now > item.expiresAt) {
                        store.delete(key);
                        cleaned++;
                    }
                }
                this.updateStats(layer);
            }
            return success(cleaned);
        }
        catch (error) {
            return failure(createError(ErrorCode.INTERNAL, `Failed to cleanup memory: ${error instanceof Error ? error.message : String(error)}`));
        }
    }
    /**
     * Check if latency SLA is met for a layer
     */
    checkLatencySLA(layer, latencyMs) {
        const sla = this.config.latencySLA[layer];
        return latencyMs <= sla * 1000;
    }
    /**
     * Promote an item to a higher layer
     */
    async promote(fromLayer, toLayer, key) {
        try {
            // Get from source layer
            const item = await this.get(fromLayer, key);
            if (!item.ok || item.data === null) {
                return failure(createError(ErrorCode.NOT_FOUND, `Item not found in layer ${fromLayer}`));
            }
            // Copy to target layer
            await this.set(toLayer, key, item.data);
            // Delete from source
            await this.delete(fromLayer, key);
            return success(undefined);
        }
        catch (error) {
