 * Self Evolution Engine - 核心進化演算法
 *
 * DSPy + GEPA implementation
 * Pattern 5: Compress (Recovery pointer for truncation)
 * Pattern 12: Long-Running Agents (Initializer pattern)
 */
import { success, failure } from '../core/result.js';
import { createError, ErrorCode } from '../core/error.js';
import { evolutionId } from '../store/typed-id.js';
import { applyAllMutations } from './mutations.js';
export const DEFAULT_CONFIG = {
    iterations: 10,
    maxCandidates: 10,
    scoreThreshold: 0.7,
    successRateThreshold: 0.6,
    verificationCount: 20,
    degradationThreshold: 0.5,
    rollbackOnDegradation: true,
};
// ============================================================================
// Evolution Engine
// ============================================================================
export class SelfEvolutionEngine {
    config;
    evolutionStore;
    traceStore;
    constructor(evolutionStore, traceStore, config = DEFAULT_CONFIG) {
        this.config = config;
        this.evolutionStore = evolutionStore;
        this.traceStore = traceStore;
    }
    /**
     * Evolve a single skill
     *
     * Flow:
     * 1. Generate candidates (GEPA)
     * 2. Score candidates (DSPy-style)
     * 3. Select best
     * 4. Verify (20 traces)
     * 5. Apply or rollback
     */
    async evolveSkill(skillSlug, currentContent) {
        // Phase 1: Generate candidates
        const candidates = this.generateCandidates(currentContent);
        // Create evolution record
        const record = {
            id: evolutionId(skillSlug),
            skillSlug,
            createdAt: Date.now(),
            status: 'running',
            triggeredBy: 'scheduler',
            candidates: candidates.map((content, i) => ({
                id: `candidate-${i}`,
                content,
                mutations: [],
            })),
        };
        // Save pending evolution
        await this.evolutionStore.saveEvolution(record);
        // Phase 2: Score candidates (parallel)
        const scoredCandidates = await this.scoreCandidates(skillSlug, record.candidates);
        // Sort by score
        scoredCandidates.sort((a, b) => (b.score ?? 0) - (a.score ?? 0));
        // Update record with scores
        record.candidates = scoredCandidates;
        record.bestCandidate = scoredCandidates[0];
        // Phase 3: Verify best candidate
        const verified = await this.verify(record.bestCandidate, skillSlug);
        if (!verified.ok || verified.data.score < this.config.degradationThreshold) {
            record.status = 'failed';
            record.error = verified.ok
                ? `Verified score ${verified.data.score} below threshold ${this.config.degradationThreshold}`
                : verified.error.message;
            await this.evolutionStore.saveEvolution(record);
            return failure(createError(ErrorCode.EVOLUTION_FAILED, record.error));
        }
        // Phase 4: Apply
        record.bestCandidate.score = verified.data.score;
        record.bestCandidate.evaluatedAt = Date.now();
        record.verifiedAt = Date.now();
        record.finalScore = verified.data.score;
        record.status = 'completed';
        await this.evolutionStore.saveEvolution(record);
        return success(record);
    }
    /**
     * Generate mutation candidates (GEPA)
     */
    generateCandidates(content) {
        return applyAllMutations(content).slice(0, this.config.maxCandidates);
    }
    /**
     * Score candidates (parallel evaluation)
     */
    async scoreCandidates(skillSlug, candidates) {
        // Get traces for scoring
        const tracesResult = await this.traceStore.getTraces(skillSlug);
        const traces = tracesResult.ok ? tracesResult.data : [];
        // Calculate success rate
        const successRate = traces.length > 0
            ? traces.filter(t => t.success).length / traces.length
            : 0.5; // Default to 0.5 if no traces
        // Score candidates in parallel (Pattern 11: Multi-Agent Research)
        const results = await Promise.allSettled(candidates.map(candidate => this.scoreCandidate(candidate, traces, successRate)));
        // Apply scores
        return candidates.map((candidate, i) => {
            const result = results[i];
            if (result.status === 'fulfilled') {
                return { ...candidate, score: result.value };
            }
            return { ...candidate, score: 0.5, rejectedReason: String(result.reason) };
        });
    }
    /**
     * Score a single candidate
     */
    async scoreCandidate(candidate, traces, successRate) {
        let score = 0.5; // Base score
        // Factor 1: Content quality heuristics
        if (candidate.content.includes('## Constraints'))
            score += 0.1;
        if (candidate.content.includes('## Example'))
            score += 0.1;
        if (candidate.content.length > 500)
            score += 0.05;
        if (candidate.content.length < 50)
            score -= 0.1;
        // Factor 2: Structure quality
        if (candidate.content.includes('# ') && candidate.content.includes('## ')) {
            score += 0.1; // Has both h1 and h2
