        // Factor 3: Success rate from traces
        score = score * 0.5 + successRate * 0.5;
        return Math.max(0, Math.min(1, score));
    }
    /**
     * Verify candidate with traces (closed-loop)
     */
    async verify(candidate, skillSlug) {
        if (!candidate) {
            return failure(createError(ErrorCode.CANDIDATE_REJECTED, 'No candidate to verify'));
        }
        // Get recent traces for verification
        const tracesResult = await this.traceStore.getTraces(skillSlug, this.config.verificationCount);
        if (!tracesResult.ok) {
            return failure(tracesResult.error);
        }
        const traces = tracesResult.data;
        if (traces.length < 3) {
            // Not enough traces for verification
            return success({ score: candidate.score ?? 0.5 });
        }
        // Calculate verified success rate
        const successCount = traces.filter(t => t.success).length;
        const verifiedRate = successCount / traces.length;
        // Combine with candidate score
        const finalScore = (candidate.score ?? 0.5) * 0.3 + verifiedRate * 0.7;
