    async rollback(skillSlug) {
        const latest = await this.evolutionStore.getLatestEvolution(skillSlug);
        if (!latest.ok || !latest.data) {
            return failure(createError(ErrorCode.NOT_FOUND, `No evolution found for ${skillSlug}`));
        }
        if (latest.data.status !== 'failed') {
            return failure(createError(ErrorCode.VALIDATION_FAILED, 'Can only rollback failed evolutions'));
        }
        // Mark as rolled back
        latest.data.status = 'rolled_back';
        await this.evolutionStore.saveEvolution(latest.data);
        return success(undefined);
    }
    /**
     * Check if evolution should be triggered
     */
    async shouldEvolve(skillSlug) {
        const tracesResult = await this.traceStore.getSuccessRate(skillSlug);
        if (!tracesResult.ok) {
            return failure(tracesResult.error);
        }
        const successRate = tracesResult.data;
        return success(successRate < this.config.successRateThreshold);
    }
}
