 * Skill Manager - 技能發現與管理
 *
 * Pattern 2: Skill Runtime (Lazy-load, trigger前置)
 * Pattern 4: Select (Memoize promise not result)
 */
import { readdir, readFile } from 'node:fs/promises';
import { join } from 'node:path';
import { success, failure } from '../core/result.js';
import { createError, ErrorCode } from '../core/error.js';
import { createTypedId } from '../store/typed-id.js';
import { memoize } from '../core/memoize.js';
function parseSkillMarkdown(content, path) {
    // Simple front-matter parser
    const match = content.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
    if (!match) {
        return failure(createError(ErrorCode.SKILL_PARSE_FAILED, 'No front-matter found'));
    }
    try {
        const yamlContent = match[1];
        const body = match[2];
        const yaml = parseYaml(yamlContent);
        return success({
            id: createTypedId('skill', yaml.slug, { version: parseInt(yaml.version, 10) || 1 }),
            slug: yaml.slug,
            name: yaml.name,
            version: yaml.version,
            description: yaml.description,
            path,
            content,
            metadata: {
                tags: yaml.metadata?.tags,
                relatedSkills: yaml.metadata?.related_skills,
                author: yaml.metadata?.author,
            },
        });
    }
    catch (error) {
        return failure(createError(ErrorCode.SKILL_PARSE_FAILED, `Failed to parse ${path}: ${error instanceof Error ? error.message : String(error)}`));
    }
}
function parseYaml(content) {
    // Simple YAML parser for our format
    const result = {};
    const lines = content.split('\n');
    for (const line of lines) {
        const colonIndex = line.indexOf(':');
        if (colonIndex === -1)
            continue;
        const key = line.slice(0, colonIndex).trim();
        let value = line.slice(colonIndex + 1).trim();
        // Handle array syntax: [item1, item2]
        if (value.startsWith('[') && value.endsWith(']')) {
            const arr = value.slice(1, -1).split(',').map(v => v.trim());
            result[key] = arr;
        }
        else {
            result[key] = value;
        }
    }
    return result;
}
// ============================================================================
// Skill Manager Implementation
// ============================================================================
export class SkillManagerImpl {
    skillsDir;
    memoizedDiscover;
    constructor(skillsDir) {
        this.skillsDir = skillsDir;
        // Pattern 4: Memoize promise, not result
        this.memoizedDiscover = memoize(() => this.doDiscover(), { maxAge: 5 * 60 * 1000 } // 5 minutes
        );
    }
    /**
     * Discover all skills (lazy-load)
     */
    async discover() {
        try {
            const skills = await this.memoizedDiscover.get();
            return success(skills);
        }
        catch (error) {
            return failure(createError(ErrorCode.INTERNAL, `Failed to discover skills: ${error instanceof Error ? error.message : String(error)}`));
        }
    }
    /**
     * Get cached skills (Pattern 4: Select)
     */
    async getSkills() {
        return this.discover();
    }
    /**
     * Get a specific skill by slug
     */
    async getSkill(slug) {
        const skills = await this.discover();
        if (!skills.ok) {
            return skills;
        }
        const skill = skills.data.find(s => s.slug === slug);
        if (!skill) {
            return failure(createError(ErrorCode.SKILL_NOT_FOUND, `Skill not found: ${slug}`));
        }
        return success(skill);
    }
    /**
     * Read skill content
     */
    async readContent(skill) {
        try {
            const content = await readFile(skill.path, 'utf-8');
            return success(content);
        }
        catch (error) {
            return failure(createError(ErrorCode.SKILL_PARSE_FAILED, `Failed to read ${skill.path}: ${error instanceof Error ? error.message : String(error)}`));
        }
    }
    /**
     * Invalidate cache (force re-discover)
     */
    invalidate() {
        this.memoizedDiscover.invalidate();
    }
    // ==========================================================================
    // Private Methods
    // ==========================================================================
    async doDiscover() {
        const skills = [];
        // Recursively find all SKILL.md files
        const entries = await readdir(this.skillsDir, { withFileTypes: true });
        for (const entry of entries) {
            if (entry.isDirectory()) {
                const skillPath = join(this.skillsDir, entry.name, 'SKILL.md');
                try {
                    const content = await readFile(skillPath, 'utf-8');
                    const result = parseSkillMarkdown(content, skillPath);
                    if (result.ok) {
                        skills.push(result.data);
                    }
                }
                catch {
                    // Skip if SKILL.md doesn't exist
                }
            }
        }
        return skills;
    }
}
// ============================================================================
// Factory
// ============================================================================
export function createSkillManager(skillsDir) {
    return new SkillManagerImpl(skillsDir);
}
