    "content": "/**
 * Memoize Utilities - Pattern 4: Select (Memoize promise not result)
 *
 * 將 Promise 工廠函數記憶，避免重複執行昂貴的操作
 */
/**
 * 創建一個記憶的 Promise
 *
 * @example
 * const skillsPromise = memoize(() => discoverSkills());
 * const skills = await skillsPromise.get(); // 第一次執行
 * const skills2 = await skillsPromise.get(); // 使用快取
 * skillsPromise.invalidate(); // 使快取失效
 */
export function memoize(factory, options) {
    let promise = null;
    let timestamp = null;
    let retries = 0;
    return {
        async get() {
            if (promise === null || this.isStale()) {
                try {
                    promise = factory();
                    const result = await promise;
                    timestamp = Date.now();
                    retries = 0;
                    return result;
                }
                catch (error) {
                    // 處理重試邏輯
                    if (options?.maxRetries && retries < options.maxRetries) {
                        retries++;
                        promise = null; // 使其過期以便重試
                        await sleep(options.retryDelay ?? 100 * retries);
                        return this.get(); // 遞迴重試
                    }
                    throw error;
                }
            }
            return promise;
        },
        invalidate() {
            promise = null;
            timestamp = null;
            retries = 0;
        },
        isStale() {
            if (!options?.maxAge || timestamp === null) {
                return false;
            }
            return Date.now() - timestamp > options.maxAge;
        },
        lastUpdated() {
            return timestamp;
        },
    };
}
/**
 * 創建一個帶有計數器的記憶 Promise
 * 用於追蹤快取命中/未命中
 */
export function memoizeWithStats(factory, options) {
    const memo = memoize(factory, options);
    let hits = 0;
    let misses = 0;
    return {
        ...memo,
        get: async () => {
            if (memo.isStale() || memo.lastUpdated() === null) {
                misses++;
            }
            else {
                hits++;
            }
            return memo.get();
        },
        get hits() { return hits; },
        get misses() { return misses; },
    };
}
/**
 * 延遲載入 - 僅在首次訪問時執行
 */
export function lazy(initializer) {
    let cached = null;
    let initialized = false;
    return () => {
        if (!initialized) {
            cached = initializer();
            initialized = true;
        }
        return cached;
    };
}
/**
 * LRU Cache 實現
 */
export class LRUCache {
    maxSize;
    cache = new Map();
    timestamps = new Map();
    constructor(maxSize) {
        this.maxSize = maxSize;
    }
    get(key) {
        const value = this.cache.get(key);
        if (value !== undefined) {
            this.timestamps.set(key, Date.now());
        }
        return value;
    }
    set(key, value) {
        if (this.cache.has(key)) {
            this.cache.delete(key);
        }
        while (this.cache.size >= this.maxSize) {
            const oldestKey = this.findOldest();
            if (oldestKey !== undefined) {
                this.cache.delete(oldestKey);
                this.timestamps.delete(oldestKey);
            }
        }
        this.cache.set(key, value);
        this.timestamps.set(key, Date.now());
    }
    has(key) {
        return this.cache.has(key);
    }
    delete(key) {
        this.timestamps.delete(key);
        return this.cache.delete(key);
    }
    clear() {
        this.cache.clear();
        this.timestamps.clear();
    }
    findOldest() {
        let oldestKey;
        let oldestTime = Infinity;
        for (const [key, time] of this.timestamps) {
            if (time < oldestTime) {
                oldestTime = time;
                oldestKey = key;
            }
        }
        return oldestKey;
    }
}
// Helper function
function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}
